import React from "react";
import { Link } from "react-router-dom";
import { CAPITALIZED_SITE_NAME } from "../../site.config";
import "./PageHeader.css";

// Shared editorial header used across all project pages:
// a back-link to home on the left, a "● Project NN" tag on the right.
// `project` is the number shown in the tag. Width comes from the shared
// --page-max CSS variable (defined in index.css).
const PageHeader = ({ project }) => (
  <header className="page-header" style={{ maxWidth: 'var(--page-max)' }}>
    <Link to="/" className="page-header__back">← {CAPITALIZED_SITE_NAME}</Link>
    <span className="page-header__tag">
      <span className="page-header__dot" />
      Project {project}
    </span>
  </header>
);

export default PageHeader;
