import React, { useState } from "react";
import "./WeatherBoard.scss";

const DATA = {
  Manila: { tempC: 32, feelsC: 38, humidity: 74, windK: 12, cond: "Humid", icon: "⛅", bg: "oklch(0.95 0.03 80)", days: [["Mon", "⛅", 33, 26], ["Tue", "⛈", 30, 25], ["Wed", "🌧", 29, 25], ["Thu", "⛅", 32, 26], ["Fri", "☀️", 34, 27]] },
  Tokyo: { tempC: 19, feelsC: 18, humidity: 55, windK: 16, cond: "Clear", icon: "☀️", bg: "oklch(0.95 0.03 230)", days: [["Mon", "☀️", 21, 13], ["Tue", "⛅", 20, 14], ["Wed", "☀️", 22, 14], ["Thu", "⛅", 19, 12], ["Fri", "🌧", 17, 12]] },
  London: { tempC: 12, feelsC: 10, humidity: 81, windK: 22, cond: "Drizzle", icon: "🌧", bg: "oklch(0.94 0.02 250)", days: [["Mon", "🌧", 13, 8], ["Tue", "☁️", 12, 7], ["Wed", "🌧", 11, 8], ["Thu", "⛅", 14, 9], ["Fri", "⛅", 15, 9]] },
  "New York": { tempC: 24, feelsC: 25, humidity: 48, windK: 14, cond: "Sunny", icon: "☀️", bg: "oklch(0.95 0.035 90)", days: [["Mon", "☀️", 26, 17], ["Tue", "☀️", 27, 18], ["Wed", "⛅", 25, 17], ["Thu", "⛈", 22, 16], ["Fri", "🌧", 21, 15]] },
};
const ORDER = ["Manila", "Tokyo", "London", "New York"];

const WeatherBoard = () => {
  const [city, setCity] = useState("Manila");
  const [unit, setUnit] = useState("C");
  const [animKey, setAnimKey] = useState(0);

  const conv = (c) => (unit === "C" ? Math.round(c) : Math.round(c * 9 / 5 + 32));
  const sym = unit === "C" ? "°C" : "°F";
  const d = DATA[city];
  const today = new Date().toLocaleDateString(undefined, { weekday: "long", month: "short", day: "numeric" });

  const pickCity = (name) => { setCity(name); setAnimKey((k) => k + 1); };

  return (
    <div className="wx-page">

      <main className="wx-main">
        <div className="wx-titleblock">
          <p className="wx-kicker">React · API</p>
          <h1 className="wx-title">Weather App</h1>
        </div>

        <div className="wx-card">
          <div className="wx-toolbar">
            <div className="wx-cities">
              {ORDER.map((name) => (
                <button
                  key={name}
                  className={"wx-city" + (city === name ? " wx-city--on" : "")}
                  onClick={() => pickCity(name)}
                >
                  {name}
                </button>
              ))}
            </div>
            <button className="wx-unit" onClick={() => setUnit((u) => (u === "C" ? "F" : "C"))}>
              {unit === "C" ? "°C → °F" : "°F → °C"}
            </button>
          </div>

          <div key={animKey} className="wx-hero" style={{ background: d.bg }}>
            <div className="wx-city-name">{city}</div>
            <div className="wx-today">{today}</div>
            <div className="wx-icon">{d.icon}</div>
            <div className="wx-temp">
              <span className="wx-temp-val">{conv(d.tempC)}</span>
              <span className="wx-temp-unit">{sym}</span>
            </div>
            <div className="wx-condition">{d.cond}</div>
          </div>

          <div className="wx-stats">
            <div className="wx-stat">
              <div className="wx-stat-label">Feels</div>
              <div className="wx-stat-val">{conv(d.feelsC)}{sym}</div>
            </div>
            <div className="wx-stat">
              <div className="wx-stat-label">Humidity</div>
              <div className="wx-stat-val">{d.humidity}%</div>
            </div>
            <div className="wx-stat">
              <div className="wx-stat-label">Wind</div>
              <div className="wx-stat-val">{d.windK} km/h</div>
            </div>
          </div>

          <div className="wx-forecast">
            {d.days.map((day) => (
              <div className="wx-day" key={day[0]}>
                <span className="wx-day-name">{day[0]}</span>
                <span className="wx-day-icon">{day[1]}</span>
                <span className="wx-day-hi">{conv(day[2])}°</span>
                <span className="wx-day-lo">{conv(day[3])}°</span>
              </div>
            ))}
          </div>
        </div>

        <p className="wx-tip">Demo data — wire in any weather API to go live.</p>
      </main>
    </div>
  );
};

export default WeatherBoard;
