import React from 'react';
import CardItem from '../CardItem/CardItem';
import { cards } from './Cards.config';
import './Cards.scss';

const WORDS = ['Zero', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven',
  'Eight', 'Nine', 'Ten', 'Eleven', 'Twelve'];

// Spell out small counts; fall back to the digits beyond the lookup
const countWord = (n) => WORDS[n] ?? String(n);

const Cards = () => {
  return (
    <section className="cards">
      <div className="cards__head">
        <h2>Projects</h2>
        <span>{countWord(cards.length)} / 2024–26</span>
      </div>

      <div className="cards__items">
        {cards.map((card, i) => (
          <CardItem
            key={card.label}
            index={String(i + 1).padStart(2, '0')}
            text={card.text}
            desc={card.desc}
            tags={card.tags}
            path={'/' + card.label}
            external={card.external}
          />
        ))}
      </div>
    </section>
  );
}

export default Cards;
