import React, { useState, useRef, useEffect, useCallback } from "react";
import "./DrumMachine.css";

const KITS = [
  { key: "Q", name: "Kick", type: "kick" },
  { key: "W", name: "Snare", type: "snare" },
  { key: "E", name: "Hat", type: "hat" },
  { key: "A", name: "Clap", type: "clap" },
  { key: "S", name: "Tom", type: "tom" },
  { key: "D", name: "OpenHat", type: "openhat" },
  { key: "Z", name: "Rim", type: "rim" },
  { key: "X", name: "Cow", type: "cow" },
  { key: "C", name: "Crash", type: "crash" },
];

const DrumMachine = () => {
  const [label, setLabel] = useState("—");
  const [volume, setVolume] = useState(70);
  const [activeKey, setActiveKey] = useState(null);

  const ctxRef = useRef(null);
  const flashRef = useRef(null);
  const volumeRef = useRef(volume);
  volumeRef.current = volume;

  const ctx = useCallback(() => {
    if (!ctxRef.current) {
      ctxRef.current = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (ctxRef.current.state === "suspended") ctxRef.current.resume();
    return ctxRef.current;
  }, []);

  const gainNode = useCallback((dur, peak) => {
    const c = ctx();
    const g = c.createGain();
    const vol = (volumeRef.current / 100) * (peak == null ? 1 : peak);
    g.gain.setValueAtTime(0.0001, c.currentTime);
    g.gain.exponentialRampToValueAtTime(Math.max(vol, 0.0002), c.currentTime + 0.005);
    g.gain.exponentialRampToValueAtTime(0.0001, c.currentTime + dur);
    g.connect(c.destination);
    return g;
  }, [ctx]);

  const noise = useCallback((dur) => {
    const c = ctx();
    const buf = c.createBuffer(1, c.sampleRate * dur, c.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < data.length; i++) data[i] = Math.random() * 2 - 1;
    const src = c.createBufferSource();
    src.buffer = buf;
    return src;
  }, [ctx]);

  const play = useCallback((type) => {
    const c = ctx();
    const t = c.currentTime;
    if (type === "kick") {
      const o = c.createOscillator(); const g = gainNode(0.5, 1);
      o.frequency.setValueAtTime(150, t); o.frequency.exponentialRampToValueAtTime(45, t + 0.18);
      o.connect(g); o.start(t); o.stop(t + 0.5);
    } else if (type === "snare") {
      const n = noise(0.2); const f = c.createBiquadFilter(); f.type = "highpass"; f.frequency.value = 1200;
      const g = gainNode(0.2, 0.7); n.connect(f); f.connect(g); n.start(t); n.stop(t + 0.2);
      const o = c.createOscillator(); const g2 = gainNode(0.12, 0.4); o.frequency.value = 180; o.connect(g2); o.start(t); o.stop(t + 0.12);
    } else if (type === "hat" || type === "openhat") {
      const dur = type === "hat" ? 0.06 : 0.3;
      const n = noise(dur); const f = c.createBiquadFilter(); f.type = "highpass"; f.frequency.value = 7000;
      const g = gainNode(dur, 0.5); n.connect(f); f.connect(g); n.start(t); n.stop(t + dur);
    } else if (type === "clap") {
      const n = noise(0.2); const f = c.createBiquadFilter(); f.type = "bandpass"; f.frequency.value = 1500;
      const g = gainNode(0.18, 0.7); n.connect(f); f.connect(g); n.start(t); n.stop(t + 0.18);
    } else if (type === "tom") {
      const o = c.createOscillator(); const g = gainNode(0.4, 0.9);
      o.frequency.setValueAtTime(220, t); o.frequency.exponentialRampToValueAtTime(80, t + 0.3);
      o.connect(g); o.start(t); o.stop(t + 0.4);
    } else if (type === "rim") {
      const o = c.createOscillator(); o.type = "square"; const g = gainNode(0.06, 0.5); o.frequency.value = 440; o.connect(g); o.start(t); o.stop(t + 0.06);
    } else if (type === "cow") {
      const o = c.createOscillator(); o.type = "square"; const g = gainNode(0.16, 0.45); o.frequency.value = 560; o.connect(g); o.start(t); o.stop(t + 0.16);
      const o2 = c.createOscillator(); o2.type = "square"; const g2 = gainNode(0.16, 0.45); o2.frequency.value = 845; o2.connect(g2); o2.start(t); o2.stop(t + 0.16);
    } else if (type === "crash") {
      const n = noise(0.7); const f = c.createBiquadFilter(); f.type = "highpass"; f.frequency.value = 5000;
      const g = gainNode(0.7, 0.45); n.connect(f); f.connect(g); n.start(t); n.stop(t + 0.7);
    }
  }, [ctx, gainNode, noise]);

  const hit = useCallback((kit) => {
    play(kit.type);
    setLabel(kit.name);
    setActiveKey(kit.key);
    clearTimeout(flashRef.current);
    flashRef.current = setTimeout(() => setActiveKey(null), 140);
  }, [play]);

  useEffect(() => {
    const onKey = (e) => {
      const k = e.key.toUpperCase();
      const kit = KITS.find((x) => x.key === k);
      if (kit) hit(kit);
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [hit]);

  return (
    <div className="dm-page">

      <main className="dm-main">
        <div className="dm-titleblock">
          <p className="dm-kicker">React · Web Audio</p>
          <h1 className="dm-title">Drum Machine</h1>
        </div>

        <div className="dm-device">
          <div className="dm-readout">
            <span className="dm-readout-label">Pad</span>
            <span className="dm-readout-value">{label}</span>
          </div>

          <div className="dm-pads">
            {KITS.map((kit) => {
              const active = activeKey === kit.key;
              return (
                <button
                  key={kit.key}
                  className={"dm-pad" + (active ? " dm-pad--active" : "")}
                  onClick={() => hit(kit)}
                >
                  <span className="dm-pad-key">{kit.key}</span>
                  <span className="dm-pad-name">{kit.name}</span>
                </button>
              );
            })}
          </div>

          <div className="dm-volume">
            <span className="dm-volume-label">Volume</span>
            <input
              type="range" min="0" max="100" value={volume}
              onInput={(e) => setVolume(parseInt(e.target.value, 10))}
              onChange={(e) => setVolume(parseInt(e.target.value, 10))}
            />
            <span className="dm-volume-value">{volume}</span>
          </div>
        </div>

        <p className="dm-tip">Tap a pad or use the Q-W-E / A-S-D / Z-X-C keys.</p>
      </main>
    </div>
  );
};

export default DrumMachine;
