import './App.css';
import { BrowserRouter as Router, Switch, Route, useLocation } from 'react-router-dom';
import Home from './pages/Home';
import Calculator from './components/Calculator/Calculator';
import DrumMachine from './components/DrumMachine/DrumMachine';
import Pomodoro from './components/Pomodoro/Pomodoro';
import MarkdownPreviewer from './components/MarkdownPreviewer/MarkdownPreviewer';
import AvatarGenerator from './components/AvatarGenerator/ImageGenerator';
import ScrollToTop from './components/ScrollToTop';
import BackToTop from './components/BackToTop/BackToTop';
import WeatherBoard from './components/WeatherApp/WeatherBoard';
import Records from './components/Records/Records';
import I18nDemo from './components/I18nDemo/I18nDemo';
import ThemeToggle from './components/ThemeToggle/ThemeToggle';
import Posts from './pages/Posts';
import Post from './pages/Post';
import Planets from './pages/Planets';
import PageHeader from './components/PageHeader/PageHeader';
import { cards } from './components/Cards/Cards.config';
import { useEffect } from 'react'
import './App.css';

export const BASE_PATH = '/hi';

// Header config derived from the Projects cards.
const HEADER_META = cards.reduce((acc, card, i) => {
  if (card.external) return acc;
  acc['/' + card.label] = { project: String(i + 1).padStart(2, '0') };
  return acc;
}, {});

// Renders one PageHeader based on the current path, or nothing.
function RouteHeader() {
  const { pathname } = useLocation();
  const key = Object.keys(HEADER_META).find((p) => pathname.startsWith(p));
  return key ? <PageHeader {...HEADER_META[key]} /> : null;
}

function App() {

  // :active effect doesn't last forever when mobile's user press something 
  const isMobile = /Mobile/.test(window.navigator.userAgent)

  useEffect(() => {
    if (isMobile) {
      document.body.addEventListener('touchstart', function () { }, false);

      return () => document.body.removeEventListener('touchstart', function () { }, false)
    }
  }
    , [isMobile])


  return (
    <>
      <Router basename={ BASE_PATH }>
        <RouteHeader />
        <div className="page">
        <Switch>
          <Route path="/" exact component={Home} />
          <Route path="/calculator" exact component={Calculator} />
          <Route path="/drum-machine" component={DrumMachine} />
          <Route path="/pomodoro" component={Pomodoro} />
          <Route path="/markdown-previewer" component={MarkdownPreviewer} />
          <Route path="/avatar-generator" component={AvatarGenerator} />
          <Route path="/weather-app" component={WeatherBoard} />
          <Route path="/records" component={Records} />
          <Route path="/i18n" component={I18nDemo} />
          <Route path="/posts" exact component={Posts} />
          <Route path="/posts/:slug" component={Post} />
          <Route path="/planets" component={Planets} />
        </Switch>
        </div>
        <ScrollToTop />
        <BackToTop />
        <ThemeToggle />
      </Router>
    </>
  );
}

export default App;
